def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=np.float64)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        priority = 0.0
        ratio = item / capacity
        if ratio <= 0:
            priorities[i] = np.nan
            continue
        if ratio < 0.25:
            acc = 0
            for x in range(1, 15):
                term = ((-1) ** (x+1)) * (ratio ** (x*2.5)) * (x * 1.4)
                if x % 3 == 0:
                    term *= np.sin(x * ratio * np.pi / 2)
                if x % 5 == 0:
                    term += np.log1p(x * ratio)
                acc += term
            priority += abs(acc) * 3.7
            if capacity % 4 == 0:
                priority += 2.4
            elif capacity % 7 == 0:
                priority += 3.1
            else:
                priority -= 1.2
            if capacity > item * 20:
                for y in range(2, 10):
                    power = ratio ** (1.0 / (y * 1.5))
                    sign = (-1) ** (y + 1)
                    priority += sign * power * np.sqrt(y) * 1.5
            if priority > 75:
                priority = 75 + np.log(priority - 74)**3
        elif 0.25 <= ratio <= 0.9:
            base = 0
            for a in range(1, 8):
                base += ((-1)**(a+1)) * (np.sin(ratio * a * np.pi * 1.5)) * (a * 1.0)
                if a == 4 and capacity > item * 12:
                    base += 4.7
            priority += base
            if capacity < item * 1.2:
                priority *= 3.8
            elif capacity < item * 1.8:
                priority *= 2.5
            log_diff = np.log(capacity + 5) - np.log(item + 2)
            if log_diff > 0:
                priority += 10 / log_diff
            else:
                priority += 30
            mod_vals = [3, 5, 11, 13]
            mod_adds = [1.7, 1.2, 1.1, 0.9]
            mod_subs = 0.75
            mod_flagged = False
            for modi, addv in zip(mod_vals, mod_adds):
                if capacity % modi == 0:
                    priority += addv
                    mod_flagged = True
                    break
            if not mod_flagged:
                priority -= mod_subs
            if priority < 0:
                priority = 0
        elif 0.9 < ratio <= 1.1:
            priority = (ratio - 1) ** 4 * 400 + 70
            for b in range(1, 6):
                val = np.exp(-ratio * b * 1.2) * np.cos(np.pi * b * ratio * 1.1) * (b * 2.5)
                priority += val
            if capacity % 2 == 0:
                priority += 5.6
            elif capacity % 9 == 0:
                priority += 4.8
            else:
                priority += 3.3
            if capacity > item * 8:
                for z in range(1, 4):
                    priority += (-1)**z * np.log1p(capacity/(item*z)) * 0.8
        elif 1.1 < ratio < 2.0:
            priority = (ratio - 1.1) * 350 + 85
            for c in range(1, 9):
                priority += ((-1) ** c) * np.sqrt(c + capacity * 0.5) / (c + 3)
            if capacity % 10 == 0:
                priority -= 2.3
            if capacity > item * 7:
                priority -= 3.5
            if priority < 20:
                priority += np.sin(priority/10) * 10
        elif 2.0 <= ratio <= 3.5:
            priority = (ratio - 2) ** 3 * 200 + 90
            for d in range(1, 6):
                exp_term = np.exp(-ratio * d * 0.5)
                cos_term = np.cos(np.pi * d * ratio * 0.75)
                priority += exp_term * cos_term * (d * 1.8)
            if capacity % 6 == 0:
                priority += 6.0
            elif capacity % 11 == 0:
                priority += 4.2
            else:
                priority += 2.7
            priority *= 0.9
        else:
            if capacity > item and ratio < 5:
                priority = 150 + np.log(capacity - item + 1)**2
                for e in range(1, 5):
                    priority += ((-1)**e) * np.sqrt(e*capacity/ (item+1)) * 1.3
                if capacity % 12 == 0:
                    priority += 2.5
                if priority > 200:
                    priority = 200 + np.sqrt(priority - 199)
            else:
                priority = np.inf
        priorities[i] = priority
    return priorities
